/**
 * @agentlog/backend — MCP Server 入口（stdio 模式）
 *
 * 通过 Model Context Protocol 为 AI Agent（Cline / Roo Code 等）
 * 提供 record_agent_intent 工具，Agent 主动上报重构意图与决策逻辑，
 * 数据写入本地 SQLite（~/.agentlog/agentlog.db）。
 *
 * 启动方式：
 *   npx tsx src/mcp.ts          （开发）
 *   node dist/mcp.js            （生产）
 */

import { Server } from "@modelcontextprotocol/sdk/server/index.js";
import { StdioServerTransport } from "@modelcontextprotocol/sdk/server/stdio.js";
import {
  CallToolRequestSchema,
  ListToolsRequestSchema,
} from "@modelcontextprotocol/sdk/types.js";
import { getDatabase, closeDatabase, toJson } from "./db/database";
import { nanoid } from "nanoid";

// ─────────────────────────────────────────────
// MCP Server 主流程
// ─────────────────────────────────────────────

async function main(): Promise<void> {
  // 预热数据库（同步，失败即退出）
  getDatabase();

  const server = new Server(
    {
      name: "agentlog-mcp",
      version: "0.1.0",
    },
    {
      capabilities: {
        tools: {},
      },
    },
  );

  // ── 工具列表 ────────────────────────────────

  server.setRequestHandler(ListToolsRequestSchema, async () => {
    return {
      tools: [
        {
          name: "record_agent_intent",
          description:
            "记录 AI 重构或编写代码的上下文意图。在完成一项任务后调用此工具，将决策逻辑持久化到本地数据库。",
          inputSchema: {
            type: "object" as const,
            properties: {
              task: {
                type: "string",
                description: "当前执行的任务或目标（简要概述）",
              },
              reasoning: {
                type: "string",
                description:
                  "重构或修改代码的深度决策逻辑和原因（越详细越好）",
              },
              affected_files: {
                type: "array",
                items: { type: "string" },
                description: "受影响的文件路径列表（相对于工作区根目录）",
              },
            },
            required: ["task", "reasoning"],
          },
        },
      ],
    };
  });

  // ── 工具调用处理 ────────────────────────────

  server.setRequestHandler(CallToolRequestSchema, async (request) => {
    if (request.params.name === "record_agent_intent") {
      const task = request.params.arguments?.task as string;
      const reasoning = request.params.arguments?.reasoning as string;
      const affectedFiles =
        (request.params.arguments?.affected_files as string[]) || [];

      try {
        process.stderr.write(`[agentlog-mcp] record_agent_intent 被调用\n`);
        process.stderr.write(`[agentlog-mcp]   task=${task}\n`);
        process.stderr.write(`[agentlog-mcp]   reasoning=${reasoning?.slice(0, 80)}...\n`);
        process.stderr.write(`[agentlog-mcp]   affected_files=${JSON.stringify(affectedFiles)}\n`);

        const db = getDatabase();
        const id = nanoid();

        // 写入 agent_sessions 表，字段对齐 database.ts DDL
        const stmt = db.prepare(`
          INSERT INTO agent_sessions (
            id, provider, model, source, workspace_path,
            prompt, reasoning, response,
            affected_files, duration_ms, tags, metadata
          ) VALUES (?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?)
        `);

        stmt.run(
          id,
          "mcp",                       // provider
          "unknown",                   // model（Agent 未上报时的默认值）
          "mcp-tool-call",             // source
          process.cwd(),               // workspace_path（以进程工作目录为准）
          task,                        // prompt
          reasoning,                   // reasoning
          `[MCP] ${task}`,             // response（简短摘要）
          toJson(affectedFiles),       // affected_files
          0,                           // duration_ms
          toJson([]),                  // tags
          toJson({}),                  // metadata
        );

        process.stderr.write(`[agentlog-mcp] 写入成功 id=${id} db=${db.name}\n`);

        return {
          content: [
            {
              type: "text" as const,
              text: `意图记录成功（id=${id}），请继续工作。`,
            },
          ],
        };
      } catch (err) {
        return {
          isError: true,
          content: [
            {
              type: "text" as const,
              text: `记录失败：${err instanceof Error ? err.message : String(err)}`,
            },
          ],
        };
      }
    }

    return {
      isError: true,
      content: [
        {
          type: "text" as const,
          text: `未知工具：${request.params.name}`,
        },
      ],
    };
  });

  // ── 启动 stdio 传输 ────────────────────────

  const transport = new StdioServerTransport();
  await server.connect(transport);

  // ── 优雅退出 ────────────────────────────────

  process.on("SIGINT", async () => {
    await server.close();
    closeDatabase();
    process.exit(0);
  });

  process.on("SIGTERM", async () => {
    await server.close();
    closeDatabase();
    process.exit(0);
  });
}

main().catch((err) => {
  // stderr 供 MCP 客户端收集错误信息
  process.stderr.write(`[agentlog-mcp] 启动失败：${err}\n`);
  process.exit(1);
});

